% Projectile.m
% A program to predict whether a launched projectile hits its target.
% - Authors: Samuel J. Crawford, Brooks MacLachlan, and W. Spencer Smith
% - Note: Generated by Drasil v0.1-alpha

1;

% Calculates flight duration (s)
% - Parameter v_launch: launch speed (m/s)
% - Parameter theta: launch angle (rad)
% - Parameter g: magnitude of gravitational acceleration (m/s^2)
% - Returns: flight duration (s)
function result = func_t_flight(v_launch, theta, g)
    result = 2.0 * v_launch * sin(theta) / g;
end

% Calculates landing position (m)
% - Parameter v_launch: launch speed (m/s)
% - Parameter theta: launch angle (rad)
% - Parameter g: magnitude of gravitational acceleration (m/s^2)
% - Returns: landing position (m)
function result = func_p_land(v_launch, theta, g)
    result = 2.0 * v_launch ^ 2.0 * sin(theta) * cos(theta) / g;
end

% Calculates distance between the target position and the landing position (m)
% - Parameter p_target: target position (m)
% - Parameter p_land: landing position (m)
% - Returns: distance between the target position and the landing position (m)
function result = func_d_offset(p_target, p_land)
    result = p_land - p_target;
end

% Reads input from a file with the given file name
% - Parameter filename: name of the input file
% - Returns: launch speed (m/s)
% - Returns: launch angle (rad)
% - Returns: target position (m)
function [v_launch, theta, p_target] = get_input(filename)
    infile = fopen(filename, "r");
    fgetl(infile);
    v_launch = str2double(fgetl(infile));
    fgetl(infile);
    theta = str2double(fgetl(infile));
    fgetl(infile);
    p_target = str2double(fgetl(infile));
    fclose(infile);
end

% Verifies that input values satisfy the physical constraints
% - Parameter v_launch: launch speed (m/s)
% - Parameter theta: launch angle (rad)
% - Parameter p_target: target position (m)
function input_constraints(v_launch, theta, p_target)
    if ~(v_launch > 0.0)
        fprintf('%s', "Warning: ");
        fprintf('%s', "v_launch has value ");
        fprintf('%g', v_launch);
        fprintf('%s', ", but is suggested to be ");
        fprintf('%s', "above ");
        fprintf('%g', 0.0);
        fprintf('%s\n', ".");
    end
    if ~(0.0 < theta && theta < pi / 2.0)
        fprintf('%s', "Warning: ");
        fprintf('%s', "theta has value ");
        fprintf('%g', theta);
        fprintf('%s', ", but is suggested to be ");
        fprintf('%s', "between ");
        fprintf('%g', 0.0);
        fprintf('%s', " and ");
        fprintf('%g', pi / 2.0);
        fprintf('%s', " ((pi)/(2))");
        fprintf('%s\n', ".");
    end
    if ~(p_target > 0.0)
        fprintf('%s', "Warning: ");
        fprintf('%s', "p_target has value ");
        fprintf('%g', p_target);
        fprintf('%s', ", but is suggested to be ");
        fprintf('%s', "above ");
        fprintf('%g', 0.0);
        fprintf('%s\n', ".");
    end
end

% Writes the output values to output.txt
% - Parameter d_offset: distance between the target position and the landing position (m)
% - Parameter t_flight: flight duration (s)
function write_output(d_offset, t_flight)
    outputfile = fopen("output.txt", "w");
    fprintf(outputfile, '%s', "d_offset = ");
    fprintf(outputfile, '%g\n', d_offset);
    fprintf(outputfile, '%s', "t_flight = ");
    fprintf(outputfile, '%g\n', t_flight);
    fclose(outputfile);
end

filename = argv(){1};
g = 9.8;
epsilon = 2.0e-2;
[v_launch, theta, p_target] = get_input(filename);
input_constraints(v_launch, theta, p_target);
t_flight = func_t_flight(v_launch, theta, g);
p_land = func_p_land(v_launch, theta, g);
d_offset = func_d_offset(p_target, p_land);
write_output(d_offset, t_flight);
